+use anyhow::{anyhow, bail, Context, Result};
+use hex::FromHex;
+use x509_cert::der::Decode as _;
+
+use crate::{
+    crypto,
+    quote::QeReportBody,
+};
+
+/// Verify the QE Identity JSON signature against the issuer certificate chain.
+///
+/// The PCCS returns:
+///   - `qe_identity`: the raw JSON string of the EnclaveIdentityV2 object
+///   - `qe_identity_signature`: hex-encoded ECDSA-P256 signature over the JSON bytes
+///   - `qe_identity_issuer_chain`: PEM-encoded certificate chain (leaf first)
+pub fn verify_qe_identity_signature(
+    qe_identity_json: &str,
+    qe_identity_signature_hex: &str,
+    qe_identity_issuer_chain_pem: &str,
+) -> Result<()> {
+    // Decode the hex signature
+    let signature_bytes = hex::decode(qe_identity_signature_hex)
+        .context("Failed to decode QE Identity signature from hex")?;
+
+    // Parse the PEM certificate chain and extract the leaf (signing) certificate
+    let certs = crypto::parse_pem_chain(qe_identity_issuer_chain_pem)
+        .context("Failed to parse QE Identity issuer chain")?;
+
+    if certs.is_empty() {
+        bail!("QE Identity issuer chain is empty");
+    }
+
+    // Verify the certificate chain itself (leaf -> root)
+    crypto::verify_certificate_chain(&certs)
+        .context("QE Identity issuer certificate chain verification failed")?;
+
+    // The leaf certificate contains the public key used to sign the QE Identity JSON
+    let leaf_cert = &certs[0];
+
+    // Verify the signature over the raw JSON bytes
+    crypto::verify_p256_signature_der(
+        leaf_cert,
+        qe_identity_json.as_bytes(),
+        &signature_bytes,
+    )
+    .context("QE Identity signature is invalid")?;
+
+    Ok(())
+}
+
+/// Verify the QE Report body against the policy constraints in the QE Identity.
+///
+/// Enforces:
+///   - MRSIGNER matches the expected value from QE Identity
+///   - ISVPRODID matches the expected value
+///   - ISVSVN meets the minimum required value (isvsvnMin / tcbLevels)
+pub fn verify_qe_report_against_identity(
+    qe_report_body: &QeReportBody,
+    qe_identity: &crate::collateral::EnclaveIdentityV2,
+) -> Result<()> {
+    let identity = &qe_identity.enclave_identity;
+
+    // Verify MRSIGNER
+    let expected_mrsigner = hex::decode(&identity.mrsigner)
+        .context("Failed to decode expected MRSIGNER from QE Identity")?;
+    if qe_report_body.mr_signer.as_ref() != expected_mrsigner.as_slice() {
+        bail!(
+            "QE Report MRSIGNER mismatch: expected {}, got {}",
+            &identity.mrsigner,
+            hex::encode(&qe_report_body.mr_signer)
+        );
+    }
+
+    // Verify ISVPRODID
+    if qe_report_body.isv_prod_id != identity.isvprodid {
+        bail!(
+            "QE Report ISVPRODID mismatch: expected {}, got {}",
+            identity.isvprodid,
+            qe_report_body.isv_prod_id
+        );
+    }
+
+    // Verify ISVSVN meets the minimum TCB level requirement.
+    // The tcbLevels array is sorted in descending order; find the highest
+    // TCB level whose isvsvn is <= the report's isvsvn and ensure it is not
+    // Revoked or OutOfDate.
+    let report_isvsvn = qe_report_body.isv_svn;
+    let tcb_status = identity
+        .tcb_levels
+        .iter()
+        .filter(|level| level.tcb.isvsvn <= report_isvsvn)
+        .max_by_key(|level| level.tcb.isvsvn)
+        .ok_or_else(|| {
+            anyhow!(
+                "QE Report ISVSVN {} is below all known TCB levels",
+                report_isvsvn
+            )
+        })?;
+
+    match tcb_status.tcb_status.as_str() {
+        "UpToDate" | "SWHardeningNeeded" | "ConfigurationNeeded" | "ConfigurationAndSWHardeningNeeded" => {
+            // Acceptable statuses
+        }
+        "OutOfDate" | "OutOfDateConfigurationNeeded" => {
+            bail!(
+                "QE TCB level is OutOfDate (ISVSVN={})",
+                report_isvsvn
+            );
+        }
+        "Revoked" => {
+            bail!(
+                "QE TCB level is Revoked (ISVSVN={})",
+                report_isvsvn
+            );
+        }
+        other => {
+            bail!("Unknown QE TCB status: {}", other);
+        }
+    }
+
+    Ok(())
+}

